import numpy as np
from numpy.linalg import norm

def cosine_similarity(a, b):
    # Angle only: dot product divided by lengths
    return np.dot(a, b) / (norm(a) * norm(b))

def euclidean_distance(a, b):
    # Straight line distance (L2)
    return norm(np.array(a) - np.array(b))

def dot_product(a, b):
    # Fast, and equals cosine if a and b are normalized to length 1
    return np.dot(a, b)

